from typing import Dict, List, Optional
from collections import deque
import itertools, random


class Solution:
    # ---- Primary: BFS for UNWEIGHTED shortest path (fewest edges) ----
    def shortestPath(self, graph: Dict[str, List[str]], start: str, target: str) -> List[str]:
        if start not in graph:
            return []
        if start == target:
            return [start]

        visited = {start}
        parent: Dict[str, Optional[str]] = {start: None}
        queue = deque([start])

        while queue:
            node = queue.popleft()
            for neighbor in graph.get(node, []):
                if neighbor not in visited:
                    visited.add(neighbor)
                    parent[neighbor] = node
                    if neighbor == target:
                        return self._reconstruct(parent, target)
                    queue.append(neighbor)
        return []  # no path

    def _reconstruct(self, parent: Dict[str, Optional[str]], target: str) -> List[str]:
        path = []
        node: Optional[str] = target
        while node is not None:
            path.append(node)
            node = parent[node]
        path.reverse()
        return path

    # ---- Weighted generalization: Dijkstra ----
    def shortestPathWeighted(self, graph: Dict[str, List[tuple]], start: str, target: str):
        import heapq
        if start not in graph:
            return [], float('inf')
        dist = {start: 0}
        parent = {start: None}
        pq = [(0, start)]
        while pq:
            d, node = heapq.heappop(pq)
            if node == target:
                return self._reconstruct(parent, target), d
            if d > dist.get(node, float('inf')):
                continue
            for neighbor, w in graph.get(node, []):
                nd = d + w
                if nd < dist.get(neighbor, float('inf')):
                    dist[neighbor] = nd
                    parent[neighbor] = node
                    heapq.heappush(pq, (nd, neighbor))
        return [], float('inf')


# ---------------- Verification ----------------
s = Solution()

# Sample
g = {"A": ["B", "C"], "B": ["D"], "C": ["D", "E"], "D": ["E"], "E": []}
print("sample:", s.shortestPath(g, "A", "E"))  # expect [A,C,E]

# Edge cases
print("same node:", s.shortestPath(g, "A", "A"))  # [A]
print("no path:", s.shortestPath({"A": ["B"], "B": [], "C": []}, "A", "C"))  # []
print("missing start:", s.shortestPath(g, "Z", "A"))  # []
print("direct:", s.shortestPath(g, "A", "B"))  # [A,B]

# Brute-force oracle: enumerate all simple paths, pick min edges
def brute(graph, start, target):
    if start == target:
        return [start]
    best = None
    def dfs(node, path, seen):
        nonlocal best
        if node == target:
            if best is None or len(path) - 1 < best:
                best = len(path) - 1
            return
        for nb in graph.get(node, []):
            if nb not in seen:
                seen.add(nb); path.append(nb)
                dfs(nb, path, seen)
                path.pop(); seen.remove(nb)
    dfs(start, [start], {start})
    return best  # min edges or None

# Random stress test vs oracle (length only)
random.seed(1)
nodes = list("ABCDEFG")
for t in range(3000):
    graph = {n: [] for n in nodes}
    for u in nodes:
        for v in nodes:
            if u != v and random.random() < 0.25:
                graph[u].append(v)
    src, dst = random.choice(nodes), random.choice(nodes)
    bfs_path = s.shortestPath(graph, src, dst)
    bfs_len = len(bfs_path) - 1 if bfs_path else None
    oracle = brute(graph, src, dst)
    if bfs_len != oracle:
        print("MISMATCH", src, dst, bfs_len, oracle, graph); break
else:
    print("stress: all 3000 random cases match oracle")

# Weighted sanity: A-(1)->B-(1)->E vs A-(5)->E
wg = {"A": [("B", 1), ("E", 5)], "B": [("E", 1)], "E": []}
print("weighted:", s.shortestPathWeighted(wg, "A", "E"))  # expect [A,B,E], 2

